# Write your MySQL query statement below
with rankedDelivery as( select *, ROW_NUMBER() over (partition by customer_id order by order_date asc) as rn from delivery) SELECT ROUND(SUM(IF(order_date = customer_pref_delivery_date,1,0)) / SUM(1) * 100 ,2) immediate_percentage  FROM rankedDelivery WHERE rn = 1